function readJson(path) { return JSON.parse(readFileSync(path, "utf8")); }
function planPack(binding) { const plan = readJson("docs/closeout-pack-plan/closeout-pack-plan.json"); const fromPlan = plan.packs.find((item) => item.pack_id === binding.pack_id); if (fromPlan) return fromPlan; const manifestPath = "docs/closeout-packs/" + binding.pack_id.toLowerCase() + "/manifest.json"; if (existsSync(manifestPath)) return readJson(manifestPath).plan_binding_snapshot; return undefined; }

test("CP00-722 binding and coverage", () => { const binding = korean.KOREAN_LEGAL_CP722_PACK_BINDING; assert.equal(binding.pack_id, "CP00-722"); assert.equal(binding.unit_count, 150); const coverage = korean.validateKoreanLegalCp722ScopeContractFoundationCoverage(planPack(binding)); assert.deepEqual(coverage.errors, []); assert.deepEqual(coverage.summary.by_deliverable, korean.KOREAN_LEGAL_CP722_REQUIREMENTS.deliverable_counts); });
